  1→package com.github.yhk1038.claudecodegui.toolwindow
  2→
  3→import com.github.yhk1038.claudecodegui.actions.OpenClaudeCodeAction
  4→import com.github.yhk1038.claudecodegui.bridge.NodeProcessManager
  5→import com.github.yhk1038.claudecodegui.services.ClaudeCodeBrowserService
  6→import com.github.yhk1038.claudecodegui.services.DiffService
  7→import com.github.yhk1038.claudecodegui.services.NodeBackendService
  8→import com.intellij.ide.BrowserUtil
  9→import com.intellij.openapi.Disposable
 10→import com.intellij.openapi.application.ApplicationManager
 11→import com.intellij.openapi.options.ShowSettingsUtil
 12→import com.intellij.openapi.diagnostic.Logger
 13→import com.intellij.openapi.fileEditor.FileEditorManager
 14→import com.intellij.openapi.project.Project
 15→import com.intellij.openapi.project.ProjectManager
 16→import com.intellij.openapi.vfs.LocalFileSystem
 17→import com.intellij.ui.jcef.JBCefBrowser
 18→import com.intellij.ui.jcef.JBCefJSQuery
 19→import kotlinx.coroutines.CoroutineScope
 20→import kotlinx.coroutines.Dispatchers
 21→import kotlinx.coroutines.SupervisorJob
 22→import kotlinx.coroutines.launch
 23→import org.cef.browser.CefBrowser
 24→import org.cef.browser.CefFrame
 25→import org.cef.handler.CefDisplayHandlerAdapter
 26→import org.cef.handler.CefLifeSpanHandlerAdapter
 27→import org.cef.handler.CefLoadHandlerAdapter
 28→import java.awt.BorderLayout
 29→import java.util.UUID
 30→import javax.swing.JPanel
 31→
 32→/**
 33→ * JCEF browser panel that hosts the WebView UI.
 34→ *
 35→ * In the v4 single-backend architecture, all business logic (Claude CLI, sessions,
 36→ * settings, file I/O) lives in the Node.js backend. This panel only:
 37→ * - Manages the JCEF browser component (via [ClaudeCodeBrowserService] pooling)
 38→ * - Starts [NodeProcessManager] to spawn the Node.js backend
 39→ * - Loads `http://localhost:{port}` once the backend is ready
 40→ * - Implements [NodeProcessManager.RpcHandler] for IDE-native operations
 41→ *   (open file, diff viewer, new tab, settings) requested by the Node.js backend
 42→ * - Handles cursor CSS -> Java cursor mapping
 43→ * - Handles title changes, console logging, keyboard shortcuts, DevTools
 44→ *
 45→ * Browser instances are pooled by [ClaudeCodeBrowserService] so that tab
 46→ * move/split operations preserve all WebView state (input, scroll, dialogs).
 47→ */
 48→class ClaudeCodePanel(
 49→    private val project: Project,
 50→    private val sessionId: String = "default",
 51→    private val initialPath: String? = null
 52→) : JPanel(BorderLayout()), Disposable {
 53→
 54→    private val logger = Logger.getInstance(ClaudeCodePanel::class.java)
 55→
 56→    // Browser is owned by ClaudeCodeBrowserService, NOT by this panel.
 57→    // This allows the browser to survive dispose-recreate cycles during tab move/split.
 58→    private val browserService = ClaudeCodeBrowserService.getInstance(project)
 59→    private val holder = browserService.getOrCreate(sessionId)
 60→    private val browser: JBCefBrowser = holder.browser
 61→    private val cursorQuery: JBCefJSQuery = holder.cursorQuery
 62→    private val streamingQuery: JBCefJSQuery = holder.streamingQuery
 63→
 64→    // Title/path change callbacks delegated to BrowserHolder
 65→    // so handlers installed on first panel creation can reach the latest panel's callbacks.
 66→    var onTitleChanged: ((String) -> Unit)?
 67→        get() = holder.onTitleChanged
 68→        set(value) { holder.onTitleChanged = value }
 69→
 70→    var onPathChanged: ((String) -> Unit)?
 71→        get() = holder.onPathChanged
 72→        set(value) { holder.onPathChanged = value }
 73→
 74→    var onStreamingStateChanged: ((Boolean) -> Unit)?
 75→        get() = holder.onStreamingStateChanged
 76→        set(value) { holder.onStreamingStateChanged = value }
 77→
 78→    private val panelId = UUID.randomUUID().toString()
 79→    private val scope = CoroutineScope(SupervisorJob() + Dispatchers.Default)
 80→
 81→    private val backendService = NodeBackendService.getInstance()
 82→    private val diffService: DiffService = DiffService.getInstance(project)
 83→
 84→    // Loading label
 85→    private val loadingLabel = javax.swing.JLabel("Starting backend...").apply {
 86→        horizontalAlignment = javax.swing.SwingConstants.CENTER
 87→        font = font.deriveFont(14f)
 88→    }
 89→
 90→    // Error panel
 91→    private var errorPanel: JPanel? = null
 92→
 93→    init {
 94→        if (holder.isLoaded) {
 95→            // Browser already loaded — reattach component (tab move/split restoration)
 96→            val parent = browser.component.parent
 97→            if (parent != null && parent !== this) {
 98→                parent.remove(browser.component)
 99→            }
100→            add(browser.component, BorderLayout.CENTER)
101→            logger.info("Reattached existing JCEF browser for session: $sessionId")
102→        } else {
103→            // First load — show loading screen
104→            add(loadingLabel, BorderLayout.CENTER)
105→        }
106→
107→        // Install JCEF handlers only once per browser instance
108→        if (!holder.handlersInstalled) {
109→            setupBrowserHandlers()
110→            holder.handlersInstalled = true
111→        }
112→
113→        // Register RPC handler for this panel
114→        backendService.ensureStarted(project.basePath ?: "", panelId, createRpcHandler())
115→
116→        // Load URL only if not already loaded
117→        if (!holder.isLoaded) {
118→            scope.launch {
119→                try {
120→                    val port = backendService.awaitPort()
121→                    loadWebView(port)
122→                } catch (e: Exception) {
123→                    logger.error("Failed to start Node.js backend", e)
124→                    javax.swing.SwingUtilities.invokeLater {
125→                        showBackendError(e.message ?: "Unknown error")
126→                    }
127→                }
128→            }
129→        }
130→    }
131→
132→    // ─── Browser handlers (JCEF) ────────────────────────────────────
133→
134→    private fun setupBrowserHandlers() {
135→        // Handle CSS cursor changes from WebView
136→        cursorQuery.addHandler { cursorName: String ->
137→            val javaCursorType = when (cursorName) {
138→                "text" -> java.awt.Cursor.TEXT_CURSOR
139→                "pointer" -> java.awt.Cursor.HAND_CURSOR
140→                "move" -> java.awt.Cursor.MOVE_CURSOR
141→                "crosshair" -> java.awt.Cursor.CROSSHAIR_CURSOR
142→                "wait" -> java.awt.Cursor.WAIT_CURSOR
143→                "grab", "grabbing" -> java.awt.Cursor.MOVE_CURSOR
144→                "col-resize", "e-resize", "w-resize", "ew-resize" -> java.awt.Cursor.E_RESIZE_CURSOR
145→                "row-resize", "n-resize", "s-resize", "ns-resize" -> java.awt.Cursor.N_RESIZE_CURSOR
146→                "nw-resize", "se-resize", "nwse-resize" -> java.awt.Cursor.NW_RESIZE_CURSOR
147→                "ne-resize", "sw-resize", "nesw-resize" -> java.awt.Cursor.NE_RESIZE_CURSOR
148→                "not-allowed", "no-drop" -> java.awt.Cursor.DEFAULT_CURSOR
149→                else -> java.awt.Cursor.DEFAULT_CURSOR
150→            }
151→            javax.swing.SwingUtilities.invokeLater {
152→                browser.component.cursor = java.awt.Cursor.getPredefinedCursor(javaCursorType)
153→            }
154→            JBCefJSQuery.Response(null)
155→        }
156→
157→        // Handle streaming state changes from WebView
158→        streamingQuery.addHandler { state: String ->
159→            holder.onStreamingStateChanged?.invoke(state == "streaming")
160→            JBCefJSQuery.Response(null)
161→        }
162→
163→        // Inject scripts on page load
164→        browser.jbCefClient.addLoadHandler(object : CefLoadHandlerAdapter() {
165→            override fun onLoadEnd(browser: CefBrowser, frame: CefFrame, httpStatusCode: Int) {
166→                if (frame.isMain) {
167→                    // Mark JCEF environment so detectRuntime() in environment.ts can detect
168→                    // the JetBrains environment and select JetBrainsAdapter over BrowserAdapter.
169→                    frame.executeJavaScript("window.__JCEF__ = true;", frame.url, 0)
170→                    injectCursorTracking(frame)
171→                    injectStreamingStateBridge(frame)
172→                    installImeWorkaround()
173→                    logger.info("WebView loaded successfully")
174→                    javax.swing.SwingUtilities.invokeLater {
175→                        this@ClaudeCodePanel.browser.component.requestFocusInWindow()
176→                    }
177→                }
178→            }
179→        }, browser.cefBrowser)
180→
181→        // Title change detection, address change tracking, and console log capture
182→        browser.jbCefClient.addDisplayHandler(object : CefDisplayHandlerAdapter() {
183→            override fun onAddressChange(browser: CefBrowser?, frame: CefFrame?, url: String?) {
184→                if (url != null && frame?.isMain == true) {
185→                    try {
186→                        val uri = java.net.URI(url)
187→                        holder.onPathChanged?.invoke(uri.path)
188→                    } catch (_: Exception) { /* ignore malformed URLs */ }
189→                }
190→            }
191→
192→            override fun onTitleChange(browser: CefBrowser?, title: String?) {
193→                if (title != null && title.isNotBlank()) {
194→                    holder.onTitleChanged?.invoke(title)
195→                }
196→            }
197→
198→            override fun onConsoleMessage(
199→                browser: CefBrowser?,
200→                level: org.cef.CefSettings.LogSeverity?,
201→                message: String?,
202→                source: String?,
203→                line: Int
204→            ): Boolean {
205→                val logPrefix = "[WebView]"
206→                when (level) {
207→                    org.cef.CefSettings.LogSeverity.LOGSEVERITY_ERROR ->
208→                        logger.error("$logPrefix $message (source: $source:$line)")
209→                    org.cef.CefSettings.LogSeverity.LOGSEVERITY_WARNING ->
210→                        logger.warn("$logPrefix $message")
211→                    else ->
212→                        logger.info("$logPrefix $message")
213→                }
214→                return false
215→            }
216→        }, browser.cefBrowser)
217→
218→        // Keyboard handler: prevent IDE from intercepting WebView shortcuts
219→        browser.jbCefClient.addKeyboardHandler(
220→            WebViewKeyboardHandler(onOpenDevTools = { openDevTools() }),
221→            browser.cefBrowser
222→        )
223→
224→        // Life span handler: intercept window.open() popups and route them correctly
225→        browser.jbCefClient.addLifeSpanHandler(object : CefLifeSpanHandlerAdapter() {
226→            override fun onBeforePopup(
227→                browser: CefBrowser?,
228→                frame: CefFrame?,
229→                targetUrl: String?,
230→                targetFrameName: String?
231→            ): Boolean {
232→                if (targetUrl.isNullOrBlank()) return true
233→
234→                ApplicationManager.getApplication().invokeLater {
235→                    try {
236→                        val uri = java.net.URI(targetUrl)
237→                        val host = uri.host ?: ""
238→                        val isLocalhost = host == "localhost" || host == "127.0.0.1"
239→
240→                        if (!isLocalhost) {
241→                            // External URL — open in OS browser
242→                            logger.info("[ClaudeCodePanel] Popup blocked (external): $targetUrl -> BrowserUtil.browse")
243→                            BrowserUtil.browse(targetUrl)
244→                            return@invokeLater
245→                        }
246→
247→                        val path = uri.path ?: "/"
248→                        when {
249→                            path == "/sessions/new" || path.startsWith("/sessions/new?") -> {
250→                                logger.info("[ClaudeCodePanel] Popup blocked: $targetUrl -> new session tab")
251→                                OpenClaudeCodeAction.openSession(project, UUID.randomUUID().toString())
252→                            }
253→                            path.startsWith("/settings/") -> {
254→                                logger.info("[ClaudeCodePanel] Popup blocked: $targetUrl -> settings tab")
255→                                OpenClaudeCodeAction.openSession(project, UUID.randomUUID().toString(), "/settings/general")
256→                            }
257→                            else -> {
258→                                logger.info("[ClaudeCodePanel] Popup blocked: $targetUrl -> new tab with path $path")
259→                                OpenClaudeCodeAction.openSession(project, UUID.randomUUID().toString(), path)
260→                            }
261→                        }
262→                    } catch (e: Exception) {
263→                        logger.warn("[ClaudeCodePanel] Failed to handle popup URL: $targetUrl", e)
264→                    }
265→                }
266→                return true // Always block JCEF from opening the popup natively
267→            }
268→        }, browser.cefBrowser)
269→    }
270→
271→    /**
272→     * Inject streaming state bridge so WebView can notify Kotlin of streaming changes
273→     * via JBCefJSQuery instead of encoding state into document.title.
274→     */
275→    private fun injectStreamingStateBridge(frame: CefFrame) {
276→        val js = """
277→            (function() {
278→                window.__notifyStreamingState = function(state) {
279→                    ${streamingQuery.inject("state")}
280→                };
281→            })();
282→        """.trimIndent()
283→        frame.executeJavaScript(js, frame.url, 0)
284→    }
285→
286→    /**
287→     * Inject cursor CSS tracking script into the loaded page.
288→     */
289→    private fun injectCursorTracking(frame: CefFrame) {
290→        val js = """
291→            (function() {
292→                var lastCursor = '';
293→                document.addEventListener('mouseover', function(e) {
294→                    var cursor = window.getComputedStyle(e.target).cursor;
295→                    if (cursor !== lastCursor) {
296→                        lastCursor = cursor;
297→                        ${cursorQuery.inject("cursor")}
298→                    }
299→                }, true);
300→            })();
301→        """.trimIndent()
302→        frame.executeJavaScript(js, frame.url, 0)
303→    }
304→
305→    /**
306→     * JCEF IME NPE workaround.
307→     * Wraps InputMethodListeners with try-catch to suppress NPE from
308→     * JBCefInputMethodAdapter when replacementRange is null (macOS + JCEF + CJK IME).
309→     */
310→    private fun installImeWorkaround() {
311→        if (holder.imeWorkaroundInstalled) return
312→
313→        fun wrapListeners(component: java.awt.Component) {
314→            val listeners = component.inputMethodListeners
315→            if (listeners.isNullOrEmpty()) return
316→
317→            for (listener in listeners) {
318→                component.removeInputMethodListener(listener)
319→                component.addInputMethodListener(object : java.awt.event.InputMethodListener {
320→                    override fun inputMethodTextChanged(event: java.awt.event.InputMethodEvent?) {
321→                        try {
322→                            listener.inputMethodTextChanged(event)
323→                        } catch (e: NullPointerException) {
324→                            logger.warn("Suppressed JCEF IME NPE (replacementRange is null)", e)
325→                        }
326→                    }
327→
328→                    override fun caretPositionChanged(event: java.awt.event.InputMethodEvent?) {
329→                        try {
330→                            listener.caretPositionChanged(event)
331→                        } catch (e: NullPointerException) {
332→                            logger.warn("Suppressed JCEF IME NPE in caretPositionChanged", e)
333→                        }
334→                    }
335→                })
336→            }
337→        }
338→
339→        fun traverseAndWrap(component: java.awt.Component) {
340→            wrapListeners(component)
341→            if (component is java.awt.Container) {
342→                for (child in component.components) {
343→                    traverseAndWrap(child)
344→                }
345→            }
346→        }
347→
348→        javax.swing.SwingUtilities.invokeLater {
349→            traverseAndWrap(browser.component)
350→            holder.imeWorkaroundInstalled = true
351→            logger.info("JCEF IME NPE workaround installed")
352→        }
353→    }
354→
355→    /**
356→     * Opens the JCEF DevTools for debugging.
357→     */
358→    private fun openDevTools() {
359→        try {
360→            (browser as? com.intellij.ui.jcef.JBCefBrowserBase)?.openDevtools()
361→                ?: logger.warn("Failed to open DevTools: browser is not JBCefBrowserBase")
362→        } catch (e: Exception) {
363→            logger.error("Failed to open DevTools", e)
364→        }
365→    }
366→
367→    // ─── WebView loading ────────────────────────────────────────────
368→
369→    /**
370→     * Load the WebView URL from the Node.js backend.
371→     * Called once the backend has printed its PORT.
372→     */
373→    private fun loadWebView(port: Int) {
374→        System.err.println("[ClaudeCodePanel] loadWebView called for project: ${project.name}")
375→        System.err.println("[ClaudeCodePanel] project.basePath: ${project.basePath}")
376→
377→        val workingDirParam = project.basePath?.let {
378→            "?workingDir=${java.net.URLEncoder.encode(it, "UTF-8")}"
379→        } ?: ""
380→
381→        val pathSegment = initialPath ?: "/sessions/new"
382→        val url = "http://localhost:$port$pathSegment$workingDirParam"
383→        System.err.println("[ClaudeCodePanel] Loading URL: $url")
384→        logger.info("Loading WebView from Node.js backend: $url")
385→
386→        javax.swing.SwingUtilities.invokeLater {
387→            remove(loadingLabel)
388→            browser.loadURL(url)
389→            add(browser.component, BorderLayout.CENTER)
390→            holder.isLoaded = true
391→            revalidate()
392→            repaint()
393→        }
394→    }
395→
396→    /**
397→     * Show error when the Node.js backend fails to start.
398→     */
399→    private fun showBackendError(errorMessage: String) {
400→        remove(loadingLabel)
401→
402→        errorPanel = JPanel(BorderLayout(0, 12)).apply {
403→            border = javax.swing.BorderFactory.createEmptyBorder(40, 40, 40, 40)
404→
405→            val messageLabel = javax.swing.JLabel(
406→                "<html><div style='text-align:center;'>" +
407→                "<b>Node.js backend failed to start</b><br><br>" +
408→                "Error: $errorMessage<br><br>" +
409→                "Ensure Node.js is installed and available on PATH.<br>" +
410→                "The backend file (backend.mjs) must be built before running." +
411→                "</div></html>"
412→            ).apply {
413→                horizontalAlignment = javax.swing.SwingConstants.CENTER
414→            }
415→            add(messageLabel, BorderLayout.CENTER)
416→
417→            val retryButton = javax.swing.JButton("Retry").apply {
418→                addActionListener { retryBackendStart() }
419→            }
420→            val buttonPanel = JPanel(java.awt.FlowLayout(java.awt.FlowLayout.CENTER))
421→            buttonPanel.add(retryButton)
422→            add(buttonPanel, BorderLayout.SOUTH)
423→        }
424→        add(errorPanel!!, BorderLayout.CENTER)
425→        revalidate()
426→        repaint()
427→    }
428→
429→    /**
430→     * Retry starting the Node.js backend after a failure.
431→     */
432→    private fun retryBackendStart() {
433→        errorPanel?.let { remove(it) }
434→        errorPanel = null
435→        add(loadingLabel, BorderLayout.CENTER)
436→        revalidate()
437→        repaint()
438→
439→        backendService.restart()
440→        scope.launch {
441→            try {
442→                val port = backendService.awaitPort()
443→                loadWebView(port)
444→            } catch (e: Exception) {
445→                logger.error("Retry: Failed to start Node.js backend", e)
446→                javax.swing.SwingUtilities.invokeLater {
447→                    showBackendError(e.message ?: "Unknown error")
448→                }
449→            }
450→        }
451→    }
452→
453→    // ─── RPC Handler (IDE-native operations) ────────────────────────
454→
455→    /**
456→     * Create an RPC handler that implements IDE-native operations
457→     * requested by the Node.js backend via JSON-RPC over stdout.
458→     */
459→    private fun createRpcHandler(): NodeProcessManager.RpcHandler {
460→        return object : NodeProcessManager.RpcHandler {
461→
462→            override suspend fun openFile(path: String) {
463→                ApplicationManager.getApplication().invokeLater {
464→                    try {
465→                        val virtualFile = LocalFileSystem.getInstance().findFileByPath(path)
466→                        if (virtualFile != null) {
467→                            FileEditorManager.getInstance(project).openFile(virtualFile, true)
468→                            logger.info("Opened file: $path")
469→                        } else {
470→                            logger.warn("File not found: $path")
471→                        }
472→                    } catch (e: Exception) {
473→                        logger.error("Failed to open file: $path", e)
474→                    }
475→                }
476→            }
477→
478→            override suspend fun openDiff(
479→                filePath: String,
480→                oldContent: String,
481→                newContent: String,
482→                toolUseId: String?
483→            ) {
484→                diffService.openDiffViewer(filePath, oldContent, newContent)
485→                logger.info("Opened diff viewer: $filePath (toolUseId=$toolUseId)")
486→            }
487→
488→            override suspend fun applyDiff(
489→                filePath: String,
490→                newContent: String,
491→                toolUseId: String?
492→            ): Boolean {
493→                val result = diffService.applyDiff(filePath, newContent)
494→                logger.info("Applied diff: $filePath, success=${result.isSuccess} (toolUseId=$toolUseId)")
495→                return result.isSuccess
496→            }
497→
498→            override suspend fun rejectDiff(toolUseId: String?) {
499→                logger.info("Diff rejected (toolUseId=$toolUseId)")
500→            }
501→
502→            override suspend fun createSession(workingDir: String) {
503→                logger.info("Session cleared (workingDir=$workingDir)")
504→            }
505→
506→            override suspend fun openNewTab(workingDir: String) {
507→                ApplicationManager.getApplication().invokeLater {
508→                    val targetProject = findProjectByBasePath(workingDir) ?: project
509→                    OpenClaudeCodeAction.openSession(targetProject, UUID.randomUUID().toString())
510→                    logger.info("Opened new Claude Code session tab (workingDir=$workingDir)")
511→                }
512→            }
513→
514→            override suspend fun openSettings(workingDir: String) {
515→                ApplicationManager.getApplication().invokeLater {
516→                    val targetProject = findProjectByBasePath(workingDir) ?: project
517→                    OpenClaudeCodeAction.openSession(targetProject, UUID.randomUUID().toString(), "/settings/general")
518→                    logger.info("Opened Claude Code settings in editor tab (workingDir=$workingDir)")
519→                }
520→            }
521→
522→            override suspend fun openTerminal(workingDir: String) {
523→                ApplicationManager.getApplication().invokeLater {
524→                    try {
525→                        val widget = createTerminalTab(project, workingDir)
526→                        if (widget != null) {
527→                            sendCommandToTerminal(widget, "claude")
528→                        }
529→                        logger.info("Opened terminal with claude in: $workingDir")
530→                    } catch (e: Exception) {
531→                        logger.error("Failed to open terminal: $workingDir", e)
532→                    }
