539→            }
540→
541→            override suspend fun updatePlugin() {
542→                ApplicationManager.getApplication().invokeLater {
543→                    try {
544→                        val clazz = Class.forName("com.intellij.ide.plugins.PluginManagerConfigurable")
545→                        @Suppress("UNCHECKED_CAST")
546→                        val configurableClass = clazz as Class<out com.intellij.openapi.options.Configurable>
547→                        ShowSettingsUtil.getInstance().showSettingsDialog(
548→                            project,
549→                            configurableClass
550→                        ) { configurable ->
551→                            try {
552→                                val method = configurable.javaClass.getMethod("enableSearch", String::class.java)
553→                                method.invoke(configurable, "Claude Code with GUI")
554→                            } catch (_: Exception) {}
555→                        }
556→                        logger.info("Opened Plugins settings dialog for plugin update")
557→                    } catch (e: Exception) {
558→                        logger.error("Failed to open Plugins settings dialog", e)
559→                    }
560→                }
561→            }
562→
563→            override suspend fun requiresRestart(): Boolean {
564→                return true
565→            }
566→        }
567→    }
568→
569→    // ─── Project Helpers ─────────────────────────────────────────────
570→
571→    private fun findProjectByBasePath(basePath: String): Project? {
572→        if (basePath.isBlank()) return null
573→        return ProjectManager.getInstance().openProjects
574→            .firstOrNull { it.basePath == basePath }
575→    }
576→
577→    // ─── Terminal Helpers ────────────────────────────────────────────
578→
579→    private fun createTerminalTab(project: Project, workingDir: String): Any? {
580→        // Try new API first (253+): TerminalToolWindowTabsManager
581→        try {
582→            val tabsManagerClass = Class.forName("org.jetbrains.plugins.terminal.TerminalToolWindowTabsManager")
583→            val getInstance = tabsManagerClass.getMethod("getInstance", Project::class.java)
584→            val tabsManager = getInstance.invoke(null, project)
585→            val createTabBuilder = tabsManagerClass.getMethod("createTabBuilder")
586→            val builder = createTabBuilder.invoke(tabsManager)
587→
588→            try {
589→                val setDir = builder.javaClass.getMethod("workingDirectory", String::class.java)
590→                setDir.invoke(builder, workingDir)
591→            } catch (_: Exception) {}
592→
593→            val build = builder.javaClass.getMethod("build")
594→            val tab = build.invoke(builder)
595→            val getTerminalView = tab.javaClass.getMethod("getTerminalView")
596→            val terminalView = getTerminalView.invoke(tab)
597→            logger.info("Created terminal tab via TerminalToolWindowTabsManager (253+ API)")
598→            return terminalView
599→        } catch (_: Exception) {}
600→
601→        // Fall back to deprecated API via reflection (242~252)
602→        try {
603→            val managerClass = Class.forName("org.jetbrains.plugins.terminal.TerminalToolWindowManager")
604→            val getInstance = managerClass.getMethod("getInstance", Project::class.java)
605→            val manager = getInstance.invoke(null, project)
606→            val createShellWidget = managerClass.getMethod(
607→                "createShellWidget", String::class.java, String::class.java,
608→                Boolean::class.javaPrimitiveType, Boolean::class.javaPrimitiveType
609→            )
610→            val widget = createShellWidget.invoke(manager, workingDir, "Claude Code", true, false)
611→            logger.info("Created terminal tab via TerminalToolWindowManager.createShellWidget (legacy reflection)")
612→            return widget
613→        } catch (e: Exception) {
614→            logger.error("Failed to create terminal tab via any API", e)
615→            return null
616→        }
617→    }
618→
619→    private fun sendCommandToTerminal(widget: Any, command: String) {
620→        try {
621→            val method = widget.javaClass.getMethod("sendCommandToExecute", String::class.java)
622→            method.invoke(widget, command)
623→            return
624→        } catch (_: Exception) {}
625→
626→        try {
627→            val builderMethod = widget.javaClass.getMethod("createSendTextBuilder", String::class.java)
628→            val builder = builderMethod.invoke(widget, command)
629→            val shouldExecute = builder.javaClass.getMethod("shouldExecute")
630→            shouldExecute.invoke(builder)
631→            val send = builder.javaClass.getMethod("send")
632→            send.invoke(builder)
633→            return
634→        } catch (_: Exception) {}
635→
636→        try {
637→            val shellWidgetClass = Class.forName("org.jetbrains.plugins.terminal.ShellTerminalWidget")
638→            val toShellMethod = shellWidgetClass.getMethod(
639→                "toShellJediTermWidgetOrThrow",
640→                Class.forName("com.intellij.terminal.ui.TerminalWidget")
641→            )
642→            val shellWidget = toShellMethod.invoke(null, widget)
643→            val executeCommand = shellWidget.javaClass.getMethod("executeCommand", String::class.java)
644→            executeCommand.invoke(shellWidget, command)
645→        } catch (e: Exception) {
646→            logger.warn("All terminal command execution methods failed", e)
647→        }
648→    }
649→
650→    // ─── Lifecycle ──────────────────────────────────────────────────
651→
652→    override fun dispose() {
653→        // Detach browser component from this panel WITHOUT disposing the browser.
654→        // The browser is owned by ClaudeCodeBrowserService and survives tab move/split.
655→        // It will be reattached when a new ClaudeCodePanel is created for the same session.
656→        remove(browser.component)
657→
658→        scope.coroutineContext[kotlinx.coroutines.Job]?.cancel()
659→        backendService.releasePanel(project.basePath ?: "", panelId)
660→        // NOTE: Do NOT call Disposer.dispose(cursorQuery) or Disposer.dispose(browser).
661→        // They are managed by ClaudeCodeBrowserService and released in fileClosed().
662→        logger.info("ClaudeCodePanel disposed (browser retained in pool)")
663→    }
664→}
