@import '@vscode/codicons/dist/codicon.css';

@tailwind base;
@tailwind components;
@tailwind utilities;

@layer utilities {
  .no-scrollbar {
    -ms-overflow-style: none;
    scrollbar-width: none;
  }
  .no-scrollbar::-webkit-scrollbar {
    display: none;
  }
}

:root {
  --ide-bg: #ffffff;
  --ide-fg: #1f2937;
  --ide-border: #e5e7eb;
  --ide-accent: #3b82f6;
  --ide-error: #ef4444;
  --ide-warning: #f59e0b;
  --ide-success: #10b981;
  --ide-font-ui: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
  --ide-font-code: 'JetBrains Mono', Consolas, Monaco, monospace;
}

.dark {
  --ide-bg: #1a1a1a;
  --ide-fg: #e4e4e7;
  --ide-border: #e4e4e7;
  --ide-accent: #60a5fa;
  --ide-error: #f87171;
  --ide-warning: #fbbf24;
  --ide-success: #34d399;
  --ide-bg-secondary: #252525;
  /*--ide-text-secondary: #71717a;*/
  --ide-text-secondary: rgba(255, 255, 255, 0.58);
}

html, body, #root {
  height: 100%;
  margin: 0;
  padding: 0;
}

html, body {
  overscroll-behavior-x: none;
}

body {
  font-family: var(--ide-font-ui);
  background-color: var(--ide-bg);
  color: var(--ide-fg);
}

* {
  box-sizing: border-box;
}

