  1→import { createContext, useContext, useState, useEffect, useCallback, type ReactNode } from 'react';
  2→import { SettingsState, DEFAULT_SETTINGS } from '@/types/settings';
  3→import { useBridgeContext } from '@/contexts/BridgeContext';
  4→import { useWorkingDir } from '@/contexts/WorkingDirContext';
  5→
  6→interface SettingsContextValue {
  7→  settings: SettingsState;
  8→  scopeSettings: Partial<SettingsState>;
  9→  isLoading: boolean;
 10→  overrides: string[];
 11→  scope: 'global' | 'project';
 12→  setScope: (scope: 'global' | 'project') => void;
 13→  updateSetting: <K extends keyof SettingsState>(key: K, value: SettingsState[K]) => Promise<void>;
 14→  updateSettingWithScope: <K extends keyof SettingsState>(key: K, value: SettingsState[K], targetScope: 'global' | 'project') => Promise<void>;
 15→  resetToGlobal: <K extends keyof SettingsState>(key: K) => Promise<void>;
 16→  refreshSettings: () => Promise<void>;
 17→}
 18→
 19→const SettingsContext = createContext<SettingsContextValue | null>(null);
 20→
 21→const STORAGE_KEY = 'claude-code-settings';
 22→
 23→interface SettingsProviderProps {
 24→  children: ReactNode;
 25→}
 26→
 27→export function SettingsProvider({ children }: SettingsProviderProps) {
 28→  const [settings, setSettings] = useState<SettingsState>(DEFAULT_SETTINGS);
 29→  const [isLoading, setIsLoading] = useState(true);
 30→  const [overrides, setOverrides] = useState<string[]>([]);
 31→  const [scopeSettings, setScopeSettings] = useState<Partial<SettingsState>>({});
 32→  const [scope, setScope] = useState<'global' | 'project'>('global');
 33→  const { isConnected, send, subscribe } = useBridgeContext();
 34→  const { workingDirectory } = useWorkingDir();
